// middleware
app.use((req, res, next) => {
  const start = performance.now();
  const timings = [];
  res.locals.timing = (name, ms) => timings.push(`${name};dur=${ms}`);
  res.on('finish', () => {
    timings.push(`total;dur=${performance.now() - start}`);
    res.setHeader('Server-Timing', timings.join(', '));
  });
  next();
});

