// per request listener leak
app.use((req, res, next) => {
  emitter.on('data', sendToClient);
  // missing cleanup
});

// fix
app.use((req, res, next) => {
  function sendToClient(data) { res.write(data); }
  emitter.on('data', sendToClient);
  res.on('close', () => emitter.off('data', sendToClient));
  next();
});

